object Solution { def token_bucket_rate_limited(events: Seq[Seq[Any]], capacity: Int, refillPeriod: Int): Seq[Boolean] = { case class Bucket(tokens: Int, lastRefill: Int); val state = scala.collection.mutable.Map[String, Bucket](); events.map { event => val timestamp = asInt(event(0)); val userId = event(1).toString; var bucket = state.getOrElse(userId, Bucket(capacity, timestamp)); val elapsed = timestamp - bucket.lastRefill; if (elapsed > 0 && refillPeriod > 0) { val refills = elapsed / refillPeriod; if (refills > 0) bucket = Bucket(math.min(capacity, bucket.tokens + refills), bucket.lastRefill + refills * refillPeriod) }; val accepted = bucket.tokens >= 1; state(userId) = if (accepted) bucket.copy(tokens = bucket.tokens - 1) else bucket; accepted } }; private def asInt(value: Any): Int = value match { case n: Int => n; case n: Long => n.toInt; case n: Double => n.toInt; case _ => 0 } }
